parameters.jsCode:
const body = $json.body ?? $json;

function clean(v) {
  return v === undefined || v === null || v === '' ? null : v;
}

return [{
  json: {
    source: clean(body.source),
    channel: clean(body.channel) ?? clean(body.source),
    restaurant_slug: clean(body.restaurant_slug),
    to: clean(body.to),
    from: clean(body.from),
    phone: clean(body.phone) ?? clean(body.from),
    email: clean(body.email),
    full_name: clean(body.full_name),
    message: clean(body.message) ?? '',
    raw_message: clean(body.message) ?? '',
    intent: clean(body.intent) ?? null,
    requested_datetime: clean(body.requested_datetime),
    party_size: clean(body.party_size),
    special_request: clean(body.special_request),
    call_id: clean(body.call_id),
    call_status: clean(body.call_status)
  }
}];

messages.content:
